import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { connectSlackCredentials } from "@vercel/connect/eve";
import { slackChannel } from "eve/channels/slack";

// Replace the UID with your own Slack Connect client. See SETUP.md.
export default slackChannel({
  credentials: connectSlackCredentials("slack/daily-digest-starter"),
});

import { defineSchedule } from "eve/schedules";

import slack from "../channels/slack";

// 09:00 UTC on weekdays. Vercel evaluates cron in UTC — adjust for your
// timezone. CUSTOMIZE HERE.
export default defineSchedule({
  cron: "0 9 * * 1-5",
  async run({ receive, waitUntil, appAuth }) {
    const channelId = process.env.SLACK_DIGEST_CHANNEL_ID;
    if (!channelId) {
      console.warn(
        "daily-digest: SLACK_DIGEST_CHANNEL_ID is not set, skipping"
      );
      return;
    }
    waitUntil(
      receive(slack, {
        message:
          "Fetch today's feed with fetch_source and post the daily digest.",
        target: { channelId },
        auth: appAuth,
      })
    );
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

// CUSTOMIZE HERE: set DIGEST_FEED_URL to the RSS/Atom feed you want digested.
const DEFAULT_FEED_URL = "https://hnrss.org/frontpage";
const MAX_CHARS = 12_000;

export default defineTool({
  description:
    "Fetch the configured RSS/Atom feed and return its raw XML (truncated). Call this before writing the digest.",
  inputSchema: z.object({}),
  async execute(_input, ctx) {
    const url = process.env.DIGEST_FEED_URL ?? DEFAULT_FEED_URL;
    const response = await fetch(url, {
      signal: ctx.abortSignal,
      headers: { accept: "application/rss+xml, application/atom+xml, */*" },
    });
    if (!response.ok) {
      throw new Error(`Feed fetch failed: ${response.status} ${url}`);
    }
    const body = await response.text();
    return {
      url,
      truncated: body.length > MAX_CHARS,
      content: body.slice(0, MAX_CHARS),
    };
  },
});

import { defineEval } from "eve/evals";
import { includes } from "eve/evals/expect";

export default defineEval({
  description: "An on-demand digest fetches the feed and lists numbered items.",
  async test(t) {
    await t.send(
      "Fetch today's feed with fetch_source and post the daily digest."
    );
    t.succeeded();
    t.calledTool("fetch_source");
    t.check(t.reply, includes(/1\./)).soft();
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 180_000,
});
